import "../Stylesheets/App.css";

function App() {
  return (
    <div className="inline-flex bg-red-200 w-full h-32 align-center">
      <a className="inline-flex text-4xl font-sans font-bold bg-yellow-300 h-fit" href="#">
        Corrida dos DEVs <img src="logo.svg" alt="Corrida-dos-devs-logo" className="h-10"/>
      </a>
      <ul className="bg-blue-900 inline-flex text-right h-fit">
        <li className="te">Ranking</li>
        <li>Registro</li>
        <li>Login</li>
      </ul>
    </div>
  );
}

export default App;
